  @fn print(...)  @ 14
  @fn hex(s, alpha)  @ 18
  @fn copy(v)  @ 204
  -- PRIVATE DATA
  -- STORAGE BACKENDS
  @fn pruneUnknown(tbl)  @ 237
      -- Tolerant on load: stale keys from a rename shouldn't error.
  @fn parse(text)  @ 245
      @contract  parse failures (bad text or non-table result) fall through to {}; never raises
  @fn loadGlobal()  @ 252
  @fn saveGlobal(tbl)  @ 260
